  1→/**
  2→ * Electron Main Process — Thin Shell
  3→ *
  4→ * Responsibilities:
  5→ * - Window lifecycle (create, show, close)
  6→ * - Backend child process management
  7→ * - IPC handler registration
  8→ * - Auto-updater setup
  9→ * - Shell environment sync (macOS PATH fix)
 10→ *
 11→ * Business logic stays in the Node.js backend and agent-server — the main process
 12→ * is purely a desktop shell that spawns them and bridges native OS features.
 13→ */
 14→
 15→import { app, BrowserWindow, ipcMain, shell } from "electron";
 16→import { join } from "path";
 17→import { is } from "@electron-toolkit/utils";
 18→import { spawnBackend, stopBackend } from "./backend-process";
 19→// Agent-server is spawned by the backend process (via AGENT_SERVER_BUNDLE_PATH env var)
 20→import { registerNativeHandlers } from "./native-handlers";
 21→import { registerBrowserViewHandlers, destroyAllBrowserViews } from "./browser-views";
 22→// PTY, file watching, and browser server are now handled by the backend
 23→// via WebSocket commands — no Electron IPC needed for these.
 24→import { setupAutoUpdater } from "./auto-updater";
 25→import { syncShellEnvironment } from "./shell-env";
 26→import { setupAppMenu } from "./app-menu";
 27→import { setupTray, destroyTray } from "./tray";
 28→
 29→// ---------------------------------------------------------------------------
 30→// Single Instance Lock
 31→// ---------------------------------------------------------------------------
 32→
 33→if (!app.requestSingleInstanceLock()) {
 34→  app.quit();
 35→  process.exit(0);
 36→}
 37→
 38→let mainWindow: BrowserWindow | null = null;
 39→
 40→// ---------------------------------------------------------------------------
 41→// Window Creation
 42→// ---------------------------------------------------------------------------
 43→
 44→async function createWindow(): Promise<void> {
 45→  mainWindow = new BrowserWindow({
 46→    width: 1400,
 47→    height: 900,
 48→    minWidth: 800,
 49→    minHeight: 600,
 50→    show: false,
 51→    titleBarStyle: process.platform === "darwin" ? "hiddenInset" : "default",
 52→    trafficLightPosition: { x: 16, y: 18 },
 53→    backgroundColor: "#00000000",
 54→    transparent: process.platform === "darwin",
 55→    vibrancy: process.platform === "darwin" ? "under-window" : undefined,
 56→    ...(process.platform === "linux"
 57→      ? { icon: join(__dirname, "../../resources/icons/icon.png") }
 58→      : {}),
 59→    webPreferences: {
 60→      preload: join(__dirname, "../preload/index.mjs"),
 61→      contextIsolation: true,
 62→      nodeIntegration: false,
 63→      sandbox: false, // ESM preload requires sandbox: false (package.json "type": "module")
 64→    },
 65→  });
 66→
 67→  // Show window once renderer is ready (avoids white flash)
 68→  mainWindow.on("ready-to-show", () => {
 69→    // Window starts hidden — the renderer calls show_main_window after
 70→    // settings/onboarding state is determined.
 71→    // Safety net: force-show after 3s if the renderer hasn't called show_main_window.
 72→    setTimeout(() => {
 73→      if (mainWindow && !mainWindow.isDestroyed() && !mainWindow.isVisible()) {
 74→        console.log("[main] Safety net: force-showing window after 3s timeout");
 75→        mainWindow.show();
 76→      }
 77→    }, 3000);
 78→  });
 79→
 80→  // Open DevTools in development
 81→  if (is.dev) {
 82→    mainWindow.webContents.openDevTools({ mode: "detach" });
 83→  }
 84→
 85→  // Forward renderer console to main process stdout (dev only — avoid leaking PII in prod logs)
 86→  if (!app.isPackaged) {
 87→    mainWindow.webContents.on("console-message", (_event, level, message, line, sourceId) => {
 88→      const prefix =
 89→        level === 2 ? "[renderer:warn]" : level === 3 ? "[renderer:error]" : "[renderer]";
 90→      const source = sourceId ? ` (${sourceId.split("/").pop()}:${line})` : "";
 91→      console.log(`${prefix} ${message}${source}`);
 92→    });
 93→  }
 94→
 95→  // External links open in system browser (only allow http/https)
 96→  mainWindow.webContents.setWindowOpenHandler(({ url }) => {
 97→    try {
 98→      const parsed = new URL(url);
 99→      if (parsed.protocol === "http:" || parsed.protocol === "https:") {
100→        shell.openExternal(url);
101→      }
102→    } catch {
103→      // Ignore malformed URLs
104→    }
105→    return { action: "deny" };
106→  });
107→
108→  // Block top-level navigation to external URLs (security: prevent redirect hijacks)
109→  mainWindow.webContents.on("will-navigate", (event, url) => {
110→    const appUrl = is.dev
111→      ? process.env.ELECTRON_RENDERER_URL
112→      : `file://${join(__dirname, "../renderer")}`;
113→    if (appUrl && url.startsWith(appUrl)) return; // allow app navigation
114→    event.preventDefault();
115→    try {
116→      const parsed = new URL(url);
117→      if (parsed.protocol === "http:" || parsed.protocol === "https:") {
118→        shell.openExternal(url);
119→      }
120→    } catch {
121→      /* ignore malformed */
122→    }
123→  });
124→
125→  // Track fullscreen state for CSS selectors (.fullscreen)
126→  mainWindow.on("enter-full-screen", () => {
127→    mainWindow?.webContents.send("fullscreen-change", { isFullscreen: true });
128→  });
129→  mainWindow.on("leave-full-screen", () => {
130→    mainWindow?.webContents.send("fullscreen-change", { isFullscreen: false });
131→  });
132→
133→  // Dev: load Vite dev server. Prod: load built files.
134→  if (is.dev && process.env.ELECTRON_RENDERER_URL) {
135→    mainWindow.loadURL(process.env.ELECTRON_RENDERER_URL);
136→  } else {
137→    mainWindow.loadFile(join(__dirname, "../renderer/index.html"));
138→  }
139→}
140→
141→// ---------------------------------------------------------------------------
142→// App Lifecycle
143→// ---------------------------------------------------------------------------
144→
145→app.whenReady().then(async () => {
146→  // Debug logging to file (Electron swallows stdout/stderr in dev mode)
147→  const fs = await import("fs");
148→  const debugLogPath = join(app.getPath("temp"), "deus-debug.log");
149→  const debugLog = (msg: string) => {
150→    try {
151→      fs.appendFileSync(debugLogPath, `${new Date().toISOString()} ${msg}\n`);
152→    } catch {
153→      // Never block boot on diagnostics
154→    }
155→    console.error(msg);
156→  };
157→  debugLog("[main] App ready, starting initialization...");
158→  debugLog("[main] __dirname: " + __dirname);
159→
160→  // Set up the native app menu (File, Edit, View, Window, Help)
161→  setupAppMenu();
162→  // Fix PATH when launched from macOS Finder (login shell doesn't run)
163→  if (process.platform === "darwin") {
164→    try {
165→      await syncShellEnvironment();
166→    } catch (err) {
167→      debugLog(
168→        "[main] syncShellEnvironment failed: " + (err instanceof Error ? err.message : String(err))
169→      );
170→    }
171→  }
172→
173→  // Spawn backend as child process
174→  debugLog("[main] Spawning backend...");
175→  try {
176→    const { port: backendPort, authToken } = await spawnBackend();
177→    debugLog("[main] Backend started on port: " + backendPort);
178→
179→    // Expose backend connection info so IPC handlers can return it to renderer
180→    process.env.DEUS_BACKEND_PORT = String(backendPort);
181→    process.env.DEUS_AUTH_TOKEN = authToken;
182→
183→    // System tray icon with backend health status
184→    setupTray(backendPort);
185→  } catch (err) {
186→    debugLog("[main] Backend spawn FAILED: " + (err instanceof Error ? err.message : String(err)));
187→    const { dialog } = await import("electron");
188→    dialog.showErrorBox(
189→      "Failed to Start",
190→      `The application backend failed to start.\n\n${err instanceof Error ? err.message : String(err)}`
191→    );
192→    app.quit();
193→    return;
194→  }
195→
196→  // Agent-server is spawned by the backend process (via AGENT_SERVER_BUNDLE_PATH env var)
197→  // when AGENT_SERVER_BUNDLE_PATH env var is present.
198→
199→  // Register IPC handlers before window creation so they're ready immediately
200→  registerNativeHandlers();
201→  registerBrowserViewHandlers();
202→
203→  // Cross-window event relay — when one renderer sends an event via ipcRenderer.send(),
204→  // forward it to all OTHER windows. This enables the detached browser window to
205→  // communicate with the main window (e.g., CHAT_INSERT events).
206→  const RELAY_EVENTS = new Set([
207→    "chat-insert", // Detached browser -> main window
208→    "browser-window:workspace-change", // Main window → detached browser window
209→  ]);
210→
211→  for (const channel of RELAY_EVENTS) {
212→    ipcMain.on(channel, (event, ...args) => {
213→      for (const win of BrowserWindow.getAllWindows()) {
214→        if (win.webContents.id !== event.sender.id && !win.isDestroyed()) {
215→          win.webContents.send(channel, ...args);
216→        }
217→      }
218→    });
219→  }
220→
221→  debugLog("[main] Creating window...");
222→  // PTY, FS watching, browser server — all handled by backend now
223→
224→  await createWindow();
225→  debugLog("[main] Window created");
226→
227→  // Dev mode: swap dock icon so it's visually distinct from the production app
228→  if (is.dev && process.platform === "darwin") {
229→    try {
230→      const { nativeImage } = await import("electron");
231→      const devIconPath = join(__dirname, "../../resources/icons/icon-dev.png");
232→      const devIcon = nativeImage.createFromPath(devIconPath);
233→      if (!devIcon.isEmpty()) {
234→        app.dock?.setIcon(devIcon);
235→        debugLog("[main] Dev dock icon set (orange dot)");
236→      }
237→    } catch (err) {
238→      debugLog(
239→        "[main] Failed to set dev dock icon: " + (err instanceof Error ? err.message : String(err))
240→      );
241→    }
242→  }
243→
244→  // Auto-updater (delayed start — let the app boot first)
245→  if (!is.dev) {
246→    setTimeout(() => {
247→      if (mainWindow && !mainWindow.isDestroyed()) setupAutoUpdater(mainWindow);
248→    }, 15_000);
249→  }
250→});
251→
252→// Second instance: focus existing window
253→app.on("second-instance", () => {
254→  if (mainWindow) {
255→    if (mainWindow.isMinimized()) mainWindow.restore();
256→    mainWindow.focus();
257→  }
258→});
259→
260→// Quit when all windows are closed (all platforms including macOS)
261→app.on("window-all-closed", () => {
262→  app.quit();
263→});
264→
265→app.on("before-quit", () => {
266→  destroyTray();
267→  destroyAllBrowserViews();
268→  stopBackend();
269→});
270→
271→// Export for IPC handlers that need window reference
272→export function getMainWindow(): BrowserWindow | null {
273→  return mainWindow;
274→}
